// @ts-nocheck
import { useState } from 'react';
import { Sparkles } from 'lucide-react';
import { AiAnalysisModal } from './AiAnalysisModal';
import { isLiteEdition } from '../../lib/config';

interface Props {
  connectionId: string;
  kind: string;
  params?: any;
  identifier?: string;
  engine?: string;
  database?: string;
  title?: string;
  label?: string;
  /** Tooltip + accessibility label. */
  titleAttr?: string;
  /** Extra className for the trigger button. */
  className?: string;
  /** Icon size in px. */
  iconSize?: number;
  /** Modal width. */
  width?: string;
  disabled?: boolean;
}

/** One-line AI Analysis trigger: a Sparkles button that opens the shared
 *  AiAnalysisModal. Drop into any panel toolbar. */
export function AiAnalysisButton({
  connectionId,
  kind,
  params = {},
  identifier = '',
  engine = '',
  database,
  title: modalTitle,
  label = 'AI Analysis',
  titleAttr = 'Analizar con IA (diagnóstico y recomendaciones)',
  className = 'nv-btn !py-0.5 !text-2xs text-violet-300 border-violet-800/60 hover:bg-violet-950/40',
  iconSize = 10,
  width,
  disabled = false,
}: Props) {
  const [open, setOpen] = useState(false);
  if (isLiteEdition) return null;
  return (
    <>
      <button
        type="button"
        className={className}
        title={titleAttr}
        onClick={() => setOpen(true)}
        disabled={disabled}
      >
        <Sparkles size={iconSize} /> {label}
      </button>
      {open && (
        <AiAnalysisModal
          open={open}
          onClose={() => setOpen(false)}
          connectionId={connectionId}
          kind={kind}
          params={params}
          identifier={identifier}
          engine={engine}
          database={database}
          title={modalTitle}
          width={width}
        />
      )}
    </>
  );
}
